531	#[cfg(test)]
532	mod tests {
533	    use std::path::{Path, PathBuf};
534	
535	    use super::*;
536	    use crate::{Cli, Commands};
537	    use clap::Parser;
538	
539	    fn parse(args: &[&str]) -> FinalizeArgs {
540	        let cli = Cli::try_parse_from(args).unwrap();
541	        match cli.command {
542	            Commands::Finalize(a) => a,
543	            _ => panic!("expected Finalize"),
544	        }
545	    }
546	
547	    fn parse_err(args: &[&str]) -> String {
548	        Cli::try_parse_from(args).unwrap_err().to_string()
549	    }
550	
551	    #[test]
552	    fn no_args() {
553	        let args = parse(&["vc-x1", "finalize"]);
554	        assert_eq!(args.repo, PathBuf::from("."));
555	        assert!(args.squash.is_none());
556	        assert!(args.push.is_none());
557	        assert!(!args.detach);
558	    }
559	
560	    #[test]
561	    fn push_only() {
562	        let args = parse(&["vc-x1", "finalize", "--push", "main"]);
563	        assert!(args.squash.is_none());
564	        assert_eq!(args.push, Some("main".to_string()));
565	    }
566	
567	    #[test]
568	    fn all_opts() {
569	        let cli = Cli::try_parse_from([
570	            "vc-x1",
571	            "--log",
572	            "/tmp/test.log",
573	            "finalize",
574	            "--repo",
575	            ".claude",
576	            "--squash",
577	            "@,@-",
578	            "--push",
579	            "dev-0.14.0",
580	            "--delay",
581	            "2.5",
582	            "--detach",
583	        ])
584	        .unwrap();
585	        assert_eq!(cli.log, Some(PathBuf::from("/tmp/test.log")));
586	        if let Commands::Finalize(args) = cli.command {
587	            assert_eq!(args.repo, PathBuf::from(".claude"));
588	            assert_eq!(args.squash, Some("@,@-".to_string()));
589	            assert_eq!(args.push, Some("dev-0.14.0".to_string()));
590	            assert_eq!(args.delay, 2.5);
591	            assert!(args.detach);
592	        } else {
593	            panic!("expected Finalize");
594	        }
595	    }
596	
597	    #[test]
598	    fn bare_squash() {
599	        let args = parse(&["vc-x1", "finalize", "--squash", "--push", "main"]);
600	        assert_eq!(args.squash, Some("@,@-".to_string()));
601	        assert_eq!(args.push, Some("main".to_string()));
