201	/// Install the standard Claude Code workspace symlink for `project_dir`.
202	///
203	/// Links `~/.claude/projects/<encoded>` → `<project_dir>/.claude`.
204	/// Silent — caller is expected to announce the action (if desired)
205	/// and to include the resulting `SymLink` in any final summary
206	/// output.
207	///
208	/// Shared by `vc-x1 clone --scope=code,bot` and `vc-x1 init
209	/// --scope=code,bot`. The full `vc-x1 symlink` subcommand below
210	/// can't directly call `install` — it has different
211	/// responsibilities (`--target` / `--symlink-dir` overrides,
212	/// replace prompts, `--list`, and `sl.create(true)` vs `false`)
213	/// — but both share `default_symlink_dir` for default-path
214	/// computation.
215	pub fn install(project_dir: &Path) -> Result<SymLink, Box<dyn std::error::Error>> {
216	    let sl = SymLink::new(project_dir, Path::new(".claude"), &default_symlink_dir()?)?;
217	    sl.create(false)?;
218	    Ok(sl)
219	}
