242	pub fn symlink(args: &SymlinkArgs) -> Result<(), Box<dyn std::error::Error>> {
243	    debug!("symlink: enter");
244	    let cwd = std::env::current_dir()?;
245	
246	    let target = match &args.target {
247	        Some(t) => PathBuf::from(t),
248	        None => PathBuf::from(".claude"),
249	    };
250	
251	    let symlink_dir = match &args.symlink_dir {
252	        Some(d) => d.clone(),
253	        None => default_symlink_dir()?,
254	    };
255	
256	    let sl = SymLink::new(&cwd, &target, &symlink_dir)?;
257	
258	    // Handle interactive prompt for replacement
259	    if let SymlinkAction::Replace { ref current_target } = sl.action {
260	        info!(
261	            "Existing symlink: {} -> {}",
262	            sl.symlink_path.display(),
263	            current_target.display()
264	        );
265	        if !args.yes {
266	            let response = crate::common::prompt("Replace with new target? [y/N] ")?;
267	            if !response.eq_ignore_ascii_case("y") {
268	                return Err("aborted".into());
269	            }
270	        }
271	    }
272	
273	    if sl.action == SymlinkAction::AlreadyCorrect {
274	        info!(
275	            "Already correct: {} -> {}",
276	            sl.symlink_path.display(),
277	            sl.abs_target.display()
278	        );
279	    } else {
280	        sl.create(true)?;
281	        info!(
282	            "Created: {} -> {}",
283	            sl.symlink_path.display(),
284	            sl.abs_target.display()
285	        );
286	    }
287	
288	    if args.list {
289	        let abs_target = if target.is_absolute() {
290	            target
291	        } else {
292	            cwd.join(&target)
293	        };
294	        info!("");
295	        info!("Contents of {}:", abs_target.display());
296	        for entry in std::fs::read_dir(&abs_target)? {
297	            let entry = entry?;
298	            info!("  {}", entry.file_name().to_string_lossy());
299	        }
300	    }
301	
302	    debug!("symlink: exit");
303	    Ok(())
304	}
