1	//! The `symlink` subcommand: manage the
2	//! `~/.claude/projects/<encoded-cwd>` symlink that points Claude
3	//! Code's per-project session directory at this workspace's
4	//! `.claude` repo.
5	//!
6	//! Also home to the shared `SymLink` planner (`new` / `with_meta`
7	//! / `create`), `encode_path`, and the `install` helper that
8	//! `vc-x1 init` / `clone` reuse for dual-scope runs.
9	
10	use std::path::{Path, PathBuf};
11	
12	use clap::Args;
13	use log::{debug, info};
14	
15	use crate::context::Context;
16	
17	/// What action the symlink operation needs to take.
18	#[derive(Debug, PartialEq, Eq)]
19	pub enum SymlinkAction {
20	    /// Nothing exists at the symlink path — create it.
21	    Create,
22	    /// An existing symlink points somewhere else — caller must decide whether to replace.
23	    Replace { current_target: PathBuf },
24	    /// The symlink already points to the correct target — nothing to do.
25	    AlreadyCorrect,
26	}
27	
28	/// A planned symlink operation.
29	#[derive(Debug)]
30	pub struct SymLink {
31	    /// Absolute path to the target directory (what the symlink points to).
32	    pub abs_target: PathBuf,
33	    /// Full path of the symlink to create/replace.
34	    pub symlink_path: PathBuf,
35	    /// What action is needed.
36	    pub action: SymlinkAction,
37	}
38	
39	/// Encode a path the way Claude Code does: replace `/` and `.` with `-`.
40	pub fn encode_path(path: &str) -> String {
41	    path.replace(['/', '.'], "-")
42	}
43	
44	/// Read what exists at a path without following symlinks.
45	///
46	/// Returns:
47	/// - `None` — nothing exists
48	/// - `Some(None)` — exists but is not a symlink
49	/// - `Some(Some(target))` — symlink pointing to target
50	fn probe(path: &Path) -> Option<Option<PathBuf>> {
51	    match path.symlink_metadata() {
52	        Err(_) => None,
53	        Ok(meta) => {
54	            if meta.is_symlink() {
55	                Some(Some(std::fs::read_link(path).unwrap_or_default())) // OK: TOCTOU race after symlink_metadata; empty PathBuf forces recreate
56	            } else {
57	                Some(None)
58	            }
59	        }
60	    }
61	}
62	
63	impl SymLink {
64	    /// Plan a symlink operation by probing the filesystem.
65	    ///
66	    /// # Arguments
67	    /// * `cwd` — current working directory (used to derive the symlink name)
68	    /// * `target` — the directory the symlink should point to (resolved to absolute)
69	    /// * `symlink_dir` — parent directory for the symlink (e.g. `~/.claude/projects`)
70	    pub fn new(cwd: &Path, target: &Path, symlink_dir: &Path) -> Result<Self, String> {
71	        let abs_target = if target.is_absolute() {
72	            target.to_path_buf()
73	        } else {
74	            cwd.join(target)
75	        };
76	
77	        let cwd_str = cwd
78	            .to_str()
79	            .ok_or_else(|| "current directory path is not valid UTF-8".to_string())?;
80	        let symlink_name = encode_path(cwd_str);
81	        let symlink_path = symlink_dir.join(symlink_name);
82	
83	        let action = match probe(&symlink_path) {
84	            None => SymlinkAction::Create,
85	            Some(None) => {
86	                return Err(format!(
87	                    "'{}' exists and is not a symlink",
88	                    symlink_path.display()
89	                ));
90	            }
91	            Some(Some(current_target)) => {
92	                if current_target == abs_target {
93	                    SymlinkAction::AlreadyCorrect
94	                } else {
95	                    SymlinkAction::Replace { current_target }
96	                }
97	            }
98	        };
99	
100	        Ok(SymLink {
101	            abs_target,
102	            symlink_path,
103	            action,
104	        })
105	    }
106	
107	    /// Plan a symlink operation from pre-probed metadata (for testing).
108	    #[cfg(test)]
109	    pub fn with_meta(
110	        cwd: &Path,
111	        target: &Path,
112	        symlink_dir: &Path,
113	        symlink_meta: Option<Option<PathBuf>>,
114	    ) -> Result<Self, String> {
115	        let abs_target = if target.is_absolute() {
116	            target.to_path_buf()
117	        } else {
118	            cwd.join(target)
119	        };
120	
121	        let cwd_str = cwd
122	            .to_str()
123	            .ok_or_else(|| "current directory path is not valid UTF-8".to_string())?;
124	        let symlink_name = encode_path(cwd_str);
125	        let symlink_path = symlink_dir.join(symlink_name);
126	
127	        let action = match symlink_meta {
128	            None => SymlinkAction::Create,
129	            Some(None) => {
130	                return Err(format!(
131	                    "'{}' exists and is not a symlink",
132	                    symlink_path.display()
133	                ));
134	            }
135	            Some(Some(current_target)) => {
136	                if current_target == abs_target {
137	                    SymlinkAction::AlreadyCorrect
138	                } else {
139	                    SymlinkAction::Replace { current_target }
140	                }
141	            }
142	        };
143	
144	        Ok(SymLink {
145	            abs_target,
146	            symlink_path,
147	            action,
148	        })
149	    }
150	
151	    /// Execute the symlink operation: create the target dir if needed, create/replace the symlink.
152	    pub fn create(&self, create_target: bool) -> Result<(), String> {
153	        debug!(
154	            "symlink {} -> {}",
155	            self.symlink_path.display(),
156	            self.abs_target.display()
157	        );
158	
159	        if create_target && !self.abs_target.exists() {
160	            std::fs::create_dir_all(&self.abs_target).map_err(|e| {
161	                format!("cannot create target '{}': {e}", self.abs_target.display())
162	            })?;
163	        }
164	
165	        if let Some(parent) = self.symlink_path.parent() {
166	            std::fs::create_dir_all(parent).map_err(|e| {
167	                format!(
168	                    "cannot create symlink directory '{}': {e}",
169	                    parent.display()
170	                )
171	            })?;
172	        }
173	
174	        match &self.action {
175	            SymlinkAction::Create => {}
176	            SymlinkAction::Replace { .. } => {
177	                std::fs::remove_file(&self.symlink_path).map_err(|e| {
178	                    format!(
179	                        "cannot remove existing symlink '{}': {e}",
180	                        self.symlink_path.display()
181	                    )
182	                })?;
183	            }
184	            SymlinkAction::AlreadyCorrect => return Ok(()),
185	        }
186	
187	        #[cfg(unix)]
188	        std::os::unix::fs::symlink(&self.abs_target, &self.symlink_path).map_err(|e| {
189	            format!(
190	                "cannot create symlink '{}' -> '{}': {e}",
191	                self.symlink_path.display(),
192	                self.abs_target.display()
193	            )
194	        })?;
195	
196	        #[cfg(not(unix))]
197	        return Err("symlink creation is only supported on Unix".to_string());
198	
199	        Ok(())
200	    }
201	}
202	
203	/// `~/.claude/projects/` — the standard Claude Code symlink
