1	//! `vc-x1 clone` — clone a repo (URL or local path) into a workspace.
2	//!
3	//! - `--scope=code,bot` (default): dual-repo layout — clones code,
4	//!   derives bot source (`<source>.claude`), clones bot into
5	//!   `<target>/.claude`, creates the Claude Code symlink. Both
6	//!   sides must succeed.
7	//! - `--scope=por`: single repo into `<target>`. No `.claude/`,
8	//!   no symlink.
9	//!
10	//! TARGET shapes (all routed through `parse_target`): URL,
11	//! `owner/name` shorthand, or a local path (`./X`, `/X`, `~/X`,
12	//! `.`, `..`). Path-form is symmetric with `git clone /local/bare.git`
13	//! — useful for fixtures and CI scratch dirs.
14	//!
15	//! `clone_one` and `clone_dual` are `pub(crate)` so init's `-3`
16	//! reshape can reuse them for the "URL exists → clone" preflight
17	//! path (per `notes/chores-08.md > init + clone redesign`).
18	
19	use std::path::Path;
20	
21	use clap::Args;
22	use log::info;
23	
24	use crate::common::run;
25	use crate::options_flags::scope::{ScopeKind, parse_scope_kind};
26	use crate::symlink;
27	use crate::url::{Target, derive_name, derive_session_url, parse_target, resolve_url};
28	
29	/// CLI args for `vc-x1 clone`.
30	#[derive(Args, Debug)]
31	pub struct CloneArgs {
32	    /// Source to clone — URL, owner/name shorthand, or local path.
33	    ///
34	    /// - URL: `git@host:owner/name(.git)?`, `https://...(.git)?`
35	    /// - owner/name shorthand: resolves to
36	    ///   `git@github.com:owner/name.git`
37	    /// - Local path: `./X`, `../X`, `/X`, `~/X`, `~`, `.`, `..`
38	    ///   (passed directly to `git clone`)
39	    #[arg(value_name = "TARGET", verbatim_doc_comment)]
40	    pub target: String,
41	
42	    /// Destination dir name in cwd [default: derived from TARGET]
43	    #[arg(value_name = "NAME")]
44	    pub name: Option<String>,
45	
46	    /// What to clone: `code,bot` (dual, default) or `por` (single).
47	    #[arg(
48	        long,
49	        short,
50	        value_name = "SCOPE",
51	        value_parser = parse_scope_kind,
52	        default_value = "code,bot"
53	    )]
54	    pub scope: ScopeKind,
55	
56	    /// Dry run — show what would be done without executing.
57	    #[arg(long)]
58	    pub dry_run: bool,
59	}
60	
61	/// Top-level clone driver.
62	///
63	/// - Resolves TARGET to a concrete clone source (URL or path).
64	/// - Determines destination dir name (`[NAME]` override or
65	///   `derive_name(TARGET)`).
66	/// - Pre-checks target dir doesn't exist.
67	/// - Dispatches to `clone_one` (POR) or `clone_dual` (code,bot).
68	pub fn clone_repo(args: &CloneArgs) -> Result<(), Box<dyn std::error::Error>> {
69	    log::debug!("clone: enter");
70	
71	    let parsed = parse_target(&args.target)?;
72	    let source = match parsed {
73	        Target::Url(u) => u,
74	        Target::OwnerName(o, n) => resolve_url(&format!("{o}/{n}")),
75	        Target::Path(p) => p.to_str().ok_or("path is not valid UTF-8")?.to_string(),
76	        Target::BareName(n) => {
77	            return Err(format!(
78	                "'{n}' is a bare name — clone has no config-driven defaults; \
79	                 use 'owner/{n}', a full URL, or './{n}' for a local path"
80	            )
81	            .into());
82	        }
83	    };
84	
85	    let name = match &args.name {
86	        Some(n) => n.clone(),
87	        None => derive_name(&args.target)?,
88	    };
89	    let parent_dir = std::env::current_dir()?;
90	    let project_dir = parent_dir.join(&name);
91	
92	    if project_dir.exists() {
93	        return Err(format!("'{}' already exists", project_dir.display()).into());
94	    }
95	
96	    if args.dry_run {
97	        info!("Dry run — would execute:");
98	        match args.scope {
99	            ScopeKind::Por => {
100	                info!("  1. jj git clone --colocate {source} {name}");
101	            }
102	            ScopeKind::CodeBot => {
103	                let session_source = derive_session_url(&source);
104	                info!("  1. jj git clone --colocate {source} {name}");
105	                info!("  2. jj git clone --colocate {session_source} {name}/.claude");
106	                info!("  3. Create Claude Code symlink");
107	            }
108	        }
109	        return Ok(());
110	    }
111	
112	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
113	
114	    match args.scope {
115	        ScopeKind::Por => {
116	            clone_one(&source, &project_dir, &parent_dir)?;
117	            info!("");
118	            info!("Done! Project cloned to {}", project_dir.display());
119	            info!("  Code repo: {}", project_dir.display());
120	        }
121	        ScopeKind::CodeBot => clone_dual(&source, &project_dir, &parent_dir)?,
122	    }
123	
124	    log::debug!("clone: exit");
125	    Ok(())
126	}
127	
128	/// Clone a single repo via `jj git clone --colocate` and verify
129	/// bookmark tracking.
130	///
131	/// - `source` is the clone source (URL or local path).
132	/// - `target_dir` is the destination working repo location.
133	/// - `parent_dir` is the cwd for the `jj git clone` subprocess.
134	///
135	/// `jj git clone --colocate` does git clone + jj init + automatic
136	/// bookmark tracking in one step (unlike colocate-after-bare-git-clone,
137	/// which needs explicit `jj bookmark track`). The `verify_tracking`
138	/// call asserts the post-clone state matches expectations.
139	pub(crate) fn clone_one(
140	    source: &str,
141	    target_dir: &Path,
142	    parent_dir: &Path,
143	) -> Result<(), Box<dyn std::error::Error>> {
144	    let target_str = target_dir
145	        .to_str()
146	        .ok_or("target path is not valid UTF-8")?;
147	    info!("Cloning {source} → {target_str}...");
148	    run(
149	        "jj",
150	        &["git", "clone", "--colocate", source, target_str],
151	        parent_dir,
152	    )?;
153	    crate::common::verify_tracking(target_dir, "main")?;
154	    Ok(())
155	}
156	
157	/// Orchestrate a dual-repo clone: code via `clone_one`, bot via
158	/// `clone_one` (no graceful skip — `--scope=code,bot` requires
159	/// both sides; users who want code-only should use `--scope=por`),
160	/// then create the Claude Code symlink.
161	pub(crate) fn clone_dual(
162	    code_source: &str,
163	    target_dir: &Path,
164	    parent_dir: &Path,
165	) -> Result<(), Box<dyn std::error::Error>> {
166	    let session_source = derive_session_url(code_source);
167	    let session_dir = target_dir.join(".claude");
168	
169	    clone_one(code_source, target_dir, parent_dir)?;
170	    clone_one(&session_source, &session_dir, target_dir)?;
171	    info!("Creating Claude Code symlink...");
172	    let sl = symlink::install(target_dir)?;
173	
174	    info!("");
175	    info!("Done! Project cloned to {}", target_dir.display());
176	    info!("  Code repo:    {}", target_dir.display());
177	    info!("  Session repo: {}", session_dir.display());
178	    info!(
179	        "  Symlink:      {} -> {}",
180	        sl.symlink_path.display(),
181	        sl.abs_target.display()
182	    );
183	
184	    Ok(())
185	}
186	
187	#[cfg(test)]
188	mod tests {
189	    use super::*;
190	    use crate::{Cli, Commands};
191	    use clap::Parser;
192	
193	    fn parse(args: &[&str]) -> CloneArgs {
194	        let cli = Cli::try_parse_from(args).unwrap();
