76	/// Resolve `args` into the concrete repo list `sync_repos` operates on.
77	///
78	/// Explicit `--scope` wins; otherwise resolves via `default_scope`
79	/// against the discovered workspace root and cwd.
80	fn resolve_args_to_repos(args: &SyncArgs) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
81	    let workspace_root = find_workspace_root();
82	    let cwd = std::env::current_dir()?;
83	    let scope = match &args.scope {
84	        Some(s) => s.clone(),
85	        None => default_scope(workspace_root.as_deref(), &cwd),
86	    };
