90	/// Relationship between a local bookmark and its remote counterpart.
91	#[derive(Debug, Clone, PartialEq, Eq)]
92	pub enum State {
93	    /// Local and remote point at the same commit.
94	    UpToDate,
95	    /// Local is a strict ancestor of remote — fast-forward possible.
96	    Behind { local: String, remote: String },
97	    /// Remote is a strict ancestor of local — nothing to pull in.
98	    Ahead { local: String, remote: String },
99	    /// Neither is an ancestor of the other — needs rebase.
100	    Diverged { local: String, remote: String },
101	    /// The bookmark has no `@<remote>` counterpart.
102	    NoRemote,
