114	/// CLI entry point for the `sync` subcommand.
115	///
116	/// Thin wrapper over `sync_repos` that resolves the `-R` flag into a
117	/// concrete repo list (falling back to the dual-repo default) and
118	/// forwards the rest of the args. Tests call `sync_repos` directly
119	/// with absolute fixture paths.
120	///
121	/// When `--quiet` is set, the global log filter is temporarily clamped
122	/// to `Warn` for the duration of the call and restored on return, so
123	/// `info!` calls throughout sync (plus any subprocess-stderr routed
124	/// through `common::run`) go dark. Errors still surface at `Warn` /
125	/// `Error` so script callers don't lose diagnostics.
126	pub fn sync(args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
127	    let repos = resolve_args_to_repos(args)?;
128	    if args.quiet {
129	        let prev = log::max_level();
130	        log::set_max_level(LevelFilter::Warn);
131	        let result = sync_repos(&repos, args);
132	        log::set_max_level(prev);
133	        result
134	    } else {
135	        sync_repos(&repos, args)
136	    }
137	}
