139	/// Sync the given repos against their remotes.
140	///
141	/// Orchestrates the full flow: pre-flight clean-check on every repo,
142	/// snapshot each repo's current op id, then hand off to `run_plan` for
143	/// fetch + classify + (optional) act. On any error, revert every repo
144	/// to its snapshot op via `jj op restore` so the caller sees an atomic
145	/// "either it all went through or nothing changed" outcome.
146	///
147	/// Paths may be relative (resolved against the process cwd) or
148	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
149	/// under parallel `cargo test`.
150	pub fn sync_repos(repos: &[PathBuf], args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
151	    debug!(
152	        "sync: enter (no_check={}, bookmark={}, remote={})",
153	        args.no_check, args.bookmark, args.remote
154	    );
155	
156	    // Preflight: verify bookmark tracking on every repo before any
157	    // fetch/rebase. Implements "Non-tracking-remote bookmark detection"
158	    // — design at:
159	    //   https://github.com/winksaville/vc-x1/blob/main/notes/chores-06.md#non-tracking-remote-bookmark-detection-design
160	    for repo in repos {
161	        crate::common::verify_tracking(repo, &args.bookmark)?;
162	    }
163	
164	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
165	    for repo in repos {
166	        let op_id = current_op_id(repo)?;
167	        debug!("{}: op snapshot = {op_id}", repo.display());
168	        snapshots.push((repo.clone(), op_id));
169	    }
170	
171	    let result = run_plan(&snapshots, args);
172	
173	    if let Err(e) = &result {
174	        warn!("sync failed: {e}");
175	        warn!("reverting all repos to starting state...");
176	        for (repo, op_id) in &snapshots {
177	            match op_restore(repo, op_id) {
178	                Ok(()) => info!("  {}: reverted to op {op_id}", repo.display()),
179	                Err(re) => warn!("  {}: revert failed: {re}", repo.display()),
180	            }
181	        }
182	    }
183	
184	    debug!("sync: exit");
185	    result
186	}
