188	/// Fetch and classify each repo, then act (or not, in dry-run).
189	///
190	/// Returns `Err` on the first failure so the caller can trigger the
191	/// cross-repo revert; partial success across repos is *not* a valid
192	/// end state for this command.
193	fn run_plan(
194	    snapshots: &[(PathBuf, String)],
195	    args: &SyncArgs,
196	) -> Result<(), Box<dyn std::error::Error>> {
197	    // Phase 1 — fetch + classify silently.
198	    //
199	    // Each repo's fetch stderr is captured (rather than streamed to
200	    // `info!` via `common::run`) so we can decide after classification
201	    // whether to surface it. `jj git fetch`'s routine "Nothing
202	    // changed." chatter is the main thing we're suppressing here —
203	    // if nothing needs action, the user shouldn't see it.
204	    let mut fetched: Vec<(PathBuf, String)> = Vec::new();
205	    let mut ctxs: Vec<RepoCtx> = Vec::new();
206	    for (repo, op_id) in snapshots {
207	        let stderr = fetch_silent(repo, &args.remote)?;
208	        fetched.push((repo.clone(), stderr));
209	        let state = classify(repo, &args.bookmark, &args.remote)?;
210	        ctxs.push(RepoCtx {
211	            path: repo.clone(),
212	            op_id: op_id.clone(),
213	            state,
214	        });
215	    }
216	
217	    let any_action_needed = ctxs
218	        .iter()
219	        .any(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }));
220	
221	    // Phase 2 — emit status. `--quiet` is enforced globally via the
222	    // log-level clamp in `sync()`, so these `info!` calls are already
223	    // suppressed in scripts; we just shape the output here.
224	    if !any_action_needed {
225	        let n = ctxs.len();
226	        let noun = if n == 1 { "repo" } else { "repos" };
227	        info!("sync: {n} {noun}, all bookmarks up-to-date");
228	    } else {
229	        for (repo, stderr) in &fetched {
230	            info!("{}: fetch {}", repo.display(), args.remote);
231	            for line in stderr.lines() {
232	                info!("{line}");
233	            }
234	        }
235	        for ctx in &ctxs {
236	            log_state(&ctx.path, &ctx.state);
237	        }
238	    }
239	
240	    // Phase 3 — act (subprocess output streams through as usual).
241	    // `act_on_state` and `ensure_at_on_main` short-circuit when
242	    // `args.no_check` is false, so check mode is a true no-op here.
243	    for ctx in &ctxs {
244	        act_on_state(ctx, args)?;
245	        ensure_at_on_main(&ctx.path, &args.bookmark, args.no_check)?;
246	    }
247	
248	    // Phase 4 — check mode is fatal when action would be needed.
249	    // Apply mode (`--no-check`) ran the action above and is done.
250	    if !args.no_check && any_action_needed {
251	        let n_action = ctxs
252	            .iter()
253	            .filter(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }))
254	            .count();
255	        let noun = if n_action == 1 { "repo" } else { "repos" };
256	        return Err(format!(
257	            "sync: {n_action} {noun} need action (see above) — \
258	             resolve with `vc-x1 sync --no-check` and re-run"
259	        )
260	        .into());
261	    }
262	    Ok(())
263	}
