265	/// Fetch `repo` from `remote` without streaming subprocess output to
266	/// `info!`.
267	///
268	/// Mirrors what `common::run` would do, but returns stderr to the
269	/// caller so the caller can decide whether to surface it (verbose /
270	/// action case) or drop it (clean case). Stdout is dropped — `jj git
271	/// fetch` doesn't use it. Failure carries stderr in the error message.
272	fn fetch_silent(repo: &Path, remote: &str) -> Result<String, Box<dyn std::error::Error>> {
273	    debug!("$ jj git fetch --remote {remote} -R {}", repo.display());
274	    let output = Command::new("jj")
275	        .args(["git", "fetch", "--remote", remote, "-R", &repo_str(repo)])
276	        .output()
277	        .map_err(|e| format!("failed to run jj git fetch: {e}"))?;
278	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
279	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
280	    if !stdout.is_empty() {
281	        debug!("  {stdout}");
282	    }
283	    if !output.status.success() {
284	        return Err(format!("jj git fetch -R {} failed: {stderr}", repo.display()).into());
285	    }
286	    Ok(stderr)
287	}
