289	/// Ensure `@` is a descendant of `bookmark`, rebasing if not.
290	///
291	/// `jj git fetch` fast-forwards a tracked local bookmark to the remote
292	/// tip when local is a strict ancestor, but leaves `@` behind — still
293	/// parented on the *pre-fetch* bookmark commit. The `.claude` repo is
294	/// the motivating case: trailing session writes (e.g. `/exit`'s jsonl
295	/// tail) sit in `@`, and without this step they'd end up orphaned on a
296	/// stale branch when the remote advanced.
297	///
298	/// Skipped when `main::@` is already non-empty (i.e., `@` is already
299	/// reachable from `bookmark`). On `--no-check`, runs
300	/// `jj rebase -b @ -d <bookmark>` which carries all commits between
301	/// the old parent and `@` forward, then checks `conflicts()` — any
302	/// conflict in this step trips the outer revert the same way a
303	/// conflicted `act_on_state` rebase would.
304	fn ensure_at_on_main(
305	    repo: &Path,
306	    bookmark: &str,
307	    apply: bool,
308	) -> Result<(), Box<dyn std::error::Error>> {
309	    if revset_nonempty(repo, &format!("{bookmark}::@"))? {
310	        return Ok(());
311	    }
312	    info!("{}: rebasing @ onto '{bookmark}'", repo.display());
313	    if apply {
314	        run(
315	            "jj",
316	            &["rebase", "-b", "@", "-d", bookmark, "-R", &repo_str(repo)],
317	            Path::new("."),
318	        )?;
319	        if has_conflicts(repo)? {
320	            return Err(format!(
321	                "{}: rebase of @ onto '{bookmark}' produced conflicts",
322	                repo.display()
323	            )
324	            .into());
325	        }
326	    }
327	    Ok(())
328	}
329	
330	/// Perform the mutation corresponding to `ctx.state` when `--no-check`.
331	///
332	/// - `UpToDate` / `Ahead` / `NoRemote` → no-op (and no output, the state
333	///   was already logged by `log_state`).
334	/// - `Behind` → `jj bookmark set <b> -r <b>@<remote>` to fast-forward.
335	/// - `Diverged` → `jj rebase -b <b> -d <b>@<remote>`, then probe
336	///   `conflicts()`. A non-empty result means the rebase produced
337	///   conflicted commits; return `Err` so the outer revert restores the
338	///   pre-fetch state.
339	fn act_on_state(ctx: &RepoCtx, args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
340	    let repo = &ctx.path;
341	    let remote_rev = format!("{}@{}", args.bookmark, args.remote);
342	    match &ctx.state {
343	        State::UpToDate | State::Ahead { .. } | State::NoRemote => Ok(()),
344	        State::Behind { .. } => {
345	            if args.no_check {
346	                info!("{}: fast-forwarding '{}'", repo.display(), args.bookmark);
347	                run(
348	                    "jj",
349	                    &[
350	                        "bookmark",
351	                        "set",
352	                        &args.bookmark,
353	                        "-r",
354	                        &remote_rev,
355	                        "-R",
356	                        &repo_str(repo),
357	                    ],
358	                    Path::new("."),
359	                )?;
360	            }
361	            Ok(())
362	        }
363	        State::Diverged { local, remote } => {
364	            if args.no_check {
365	                // `local` is either a single commit id or a comma-joined list
366	                // of heads when the bookmark is conflicted. Pick the head
367	                // that isn't the remote — that's the local-only tip. The
368	                // comma-joined path covers the jj post-fetch divergence
369	                // shape (local bookmark conflicted between old local head
370	                // and freshly-fetched remote head).
371	                let local_head = local
372	                    .split(',')
373	                    .find(|h| *h != remote)
374	                    .unwrap_or(local.as_str());
375	                info!(
376	                    "{}: rebasing {local_head} onto {remote_rev}",
377	                    repo.display()
378	                );
379	                run(
380	                    "jj",
381	                    &[
382	                        "rebase",
383	                        "-b",
384	                        local_head,
385	                        "-d",
386	                        &remote_rev,
387	                        "-R",
388	                        &repo_str(repo),
389	                    ],
390	                    Path::new("."),
391	                )?;
392	                if has_conflicts(repo)? {
393	                    return Err(format!("{}: rebase produced conflicts", repo.display()).into());
394	                }
395	            }
396	            Ok(())
397	        }
398	    }
399	}
