401	/// Print a single-line summary of `state` at `info!` level.
402	fn log_state(repo: &Path, state: &State) {
403	    let r = repo.display();
404	    match state {
405	        State::UpToDate => info!("{r}: up-to-date"),
406	        State::NoRemote => info!("{r}: no remote counterpart — skipping"),
407	        State::Ahead { local, remote } => {
408	            info!("{r}: ahead (local {local} > remote {remote}); nothing to sync")
409	        }
410	        State::Behind { local, remote } => {
411	            info!("{r}: behind (local {local} < remote {remote}); would fast-forward")
412	        }
413	        State::Diverged { local, remote } => {
414	            info!("{r}: diverged (local {local} vs remote {remote}); would rebase")
415	        }
416	    }
417	}
