419	/// Return the id of the most recent operation on `repo`.
420	///
421	/// Used as the revert target on failure. Exposed at `pub(crate)` so
422	/// `push` (0.37.0-2+) can reuse the same snapshot pattern for its
423	/// commit-stage rollback without duplicating the jj invocation.
424	pub(crate) fn current_op_id(repo: &Path) -> Result<String, Box<dyn std::error::Error>> {
425	    let out = run(
426	        "jj",
427	        &[
428	            "op",
429	            "log",
430	            "--no-graph",
431	            "-n",
432	            "1",
433	            "-T",
434	            "id.short(12)",
435	            "-R",
436	            &repo_str(repo),
437	        ],
438	        Path::new("."),
439	    )?;
440	    Ok(out.trim().to_string())
441	}
442	
443	/// Restore `repo` to the operation identified by `op_id`.
444	///
445	/// Thin wrapper around `jj op restore`. Called during the failure
446	/// revert path — drops the caller's returned stdout. Exposed at
447	/// `pub(crate)` so `push` reuses the same restore call.
448	pub(crate) fn op_restore(repo: &Path, op_id: &str) -> Result<(), Box<dyn std::error::Error>> {
449	    run(
450	        "jj",
451	        &["op", "restore", op_id, "-R", &repo_str(repo)],
452	        Path::new("."),
453	    )?;
454	    Ok(())
455	}
456	
457	/// Classify the relationship between `bookmark` and `bookmark@remote`.
458	///
459	/// Uses `bookmarks(<b>)` rather than the bare name so a conflicted
460	/// bookmark (jj's representation of a diverged fetch) resolves to all
461	/// of its heads instead of erroring. When the set has multiple heads,
462	/// the bookmark is conflicted and the repo is `Diverged` by definition.
463	/// Otherwise we compare the single local head against the single
464	/// remote commit via two revset-ancestry probes.
465	///
466	/// Returns `NoRemote` when `<b>@<remote>` does not resolve — the caller
467	/// logs a skip and moves on.
468	fn classify(
469	    repo: &Path,
470	    bookmark: &str,
471	    remote: &str,
472	) -> Result<State, Box<dyn std::error::Error>> {
473	    let local_heads = local_bookmark_heads(repo, bookmark)?;
474	    let remote_rev = format!("{bookmark}@{remote}");
475	    let Some(remote) = try_commit_id(repo, &remote_rev)? else {
476	        return Ok(State::NoRemote);
477	    };
478	    if local_heads.is_empty() {
479	        return Err(format!("{}: bookmark '{bookmark}' does not exist", repo.display()).into());
480	    }
481	    if local_heads.len() > 1 {
482	        // Conflicted bookmark — jj's shape for post-fetch divergence.
483	        let local = local_heads.join(",");
484	        return Ok(State::Diverged { local, remote });
485	    }
486	    let local = local_heads.into_iter().next().unwrap(); // OK: `len() > 1` arm handled above, `is_empty()` handled above
487	    if local == remote {
488	        return Ok(State::UpToDate);
489	    }
490	    let local_is_anc = revset_nonempty(repo, &format!("{local}::{remote_rev}"))?;
491	    let remote_is_anc = revset_nonempty(repo, &format!("{remote_rev}::{local}"))?;
492	    Ok(match (local_is_anc, remote_is_anc) {
493	        (true, _) => State::Behind { local, remote },
494	        (false, true) => State::Ahead { local, remote },
495	        (false, false) => State::Diverged { local, remote },
496	    })
497	}
498	
499	/// Return all commit ids the `bookmark` currently points at.
500	///
501	/// Normally a one-element vector; two or more elements indicate a
502	/// conflicted bookmark (jj's representation of diverged post-fetch
503	/// state, where the local bookmark has multiple heads).
504	fn local_bookmark_heads(
505	    repo: &Path,
506	    bookmark: &str,
507	) -> Result<Vec<String>, Box<dyn std::error::Error>> {
508	    let out = run(
509	        "jj",
510	        &[
511	            "log",
512	            "-r",
513	            &format!("bookmarks(exact:{bookmark})"),
514	            "--no-graph",
515	            "-T",
516	            r#"commit_id.short(12) ++ "\n""#,
517	            "-R",
518	            &repo_str(repo),
519	        ],
520	        Path::new("."),
521	    )?;
522	    Ok(out
523	        .lines()
524	        .map(|l| l.trim().to_string())
525	        .filter(|l| !l.is_empty())
526	        .collect())
527	}
528	
529	/// Return the short commit id that `rev` resolves to in `repo`.
530	///
531	/// Errors when the revset is unresolvable or matches multiple heads
532	/// — callers that want to tolerate "revset doesn't resolve" should use
533	/// `try_commit_id`.
534	fn commit_id(repo: &Path, rev: &str) -> Result<String, Box<dyn std::error::Error>> {
535	    let out = run(
536	        "jj",
537	        &[
538	            "log",
539	            "-r",
540	            rev,
541	            "--no-graph",
542	            "-T",
543	            "commit_id.short(12)",
544	            "-R",
545	            &repo_str(repo),
546	        ],
547	        Path::new("."),
548	    )?;
549	    Ok(out.trim().to_string())
550	}
551	
552	/// Like `commit_id`, but `Ok(None)` when the revset doesn't resolve.
553	///
554	/// jj reports missing revisions via stderr strings like
555	/// `Revision \`foo@origin\` doesn't exist` or `No such revision …`;
556	/// both get mapped to `Ok(None)` so callers can distinguish "missing"
557	/// from "other subprocess failure".
558	fn try_commit_id(repo: &Path, rev: &str) -> Result<Option<String>, Box<dyn std::error::Error>> {
559	    match commit_id(repo, rev) {
560	        Ok(id) if id.is_empty() => Ok(None),
561	        Ok(id) => Ok(Some(id)),
562	        Err(e) => {
563	            let msg = e.to_string();
564	            if msg.contains("doesn't exist") || msg.contains("No such revision") {
565	                Ok(None)
566	            } else {
567	                Err(e)
568	            }
569	        }
570	    }
571	}
572	
573	/// Return `true` when `revset` matches at least one commit in `repo`.
574	fn revset_nonempty(repo: &Path, revset: &str) -> Result<bool, Box<dyn std::error::Error>> {
575	    let out = run(
576	        "jj",
577	        &[
578	            "log",
579	            "-r",
580	            revset,
581	            "--no-graph",
582	            "-T",
583	            r#"commit_id.short() ++ "\n""#,
584	            "-R",
585	            &repo_str(repo),
586	        ],
587	        Path::new("."),
588	    )?;
589	    Ok(!out.trim().is_empty())
590	}
591	
592	/// Return `true` when `repo` has any conflicted commits.
593	fn has_conflicts(repo: &Path) -> Result<bool, Box<dyn std::error::Error>> {
594	    revset_nonempty(repo, "conflicts()")
595	}
596	
597	/// Convert a path to a `String` suitable for passing as a subprocess arg.
598	fn repo_str(p: &Path) -> String {
599	    p.to_string_lossy().into_owned()
600	}
601	
